import{c as t,Q as a,j as r,m as n}from"./chunks/framework.BXc4yaFE.js";const w=JSON.parse('{"title":"The Rundown AI — 2026-04-29","description":"","frontmatter":{"title":"The Rundown AI — 2026-04-29","date":"2026-04-29T00:00:00.000Z","source":"The Rundown AI","type":"ai-news"},"headers":[],"relativePath":"research/ai-news/2026-04/2026-04-29-the-rundown-ai.md","filePath":"research/ai-news/2026-04/2026-04-29-the-rundown-ai.md","lastUpdated":1779898012000}'),i={name:"research/ai-news/2026-04/2026-04-29-the-rundown-ai.md"};function o(s,e,m,p,l,u){return a(),r("div",null,[...e[0]||(e[0]=[n('<h1 id="🗞️-the-rundown-ai-—-2026-04-29" tabindex="-1">🗞️ The Rundown AI — 2026-04-29 <a class="header-anchor" href="#🗞️-the-rundown-ai-—-2026-04-29" aria-label="Permalink to &quot;🗞️ The Rundown AI — 2026-04-29&quot;">​</a></h1><blockquote><p>每日 AI 產業動態，通俗易懂、密度高 來源：<a href="https://rss.beehiiv.com/feeds/2R3C6Bt5wj.xml" target="_blank" rel="noreferrer">The Rundown AI</a></p></blockquote><hr><h2 id="the-biggest-ai-trial-ever-kicks-off" tabindex="-1"><a href="https://www.therundown.ai/p/the-biggest-ai-trial-ever-kicks-off" target="_blank" rel="noreferrer">The biggest AI trial ever kicks off</a> <a class="header-anchor" href="#the-biggest-ai-trial-ever-kicks-off" aria-label="Permalink to &quot;[The biggest AI trial ever kicks off](https://www.therundown.ai/p/the-biggest-ai-trial-ever-kicks-off)&quot;">​</a></h2><p><em>🗞️ The Rundown AI | 2026-04-29</em></p><p><a href="./">Read Online</a> | <a href="https://www.therundown.ai/subscribe?utm_source=www.therundown.ai&amp;utm_medium=newsletter&amp;utm_campaign=the-biggest-ai-trial-ever-kicks-off" target="_blank" rel="noreferrer">Sign Up</a> | <a href="https://therundownai.typeform.com/to/kraZ1TSO?utm_source=www.therundown.ai&amp;utm_medium=newsletter&amp;utm_campaign=the-biggest-ai-trial-ever-kicks-off" target="_blank" rel="noreferrer">Advertise</a></p><p><a href="https://www.beams.run/?utm_source=TheRundownAI&amp;utm_medium=Newsletter&amp;utm_campaign=AI&amp;utm_content=Insertion" target="_blank" rel="noreferrer"></a></p><p>Good morning, AI enthusiasts. The two faces behind AI’s biggest rivalry are finally in the same room — but this time it&#39;s a federal courtroom, with Elon Musk on the witness stand and Sam Altman watching from the gallery.</p><p>Musk&#39;s $130B trial against OpenAI kicked off on Tuesday, with four weeks of testimony, hundreds of pages of private emails set to spill into the public record, major AI names on the stand, and a lot more drama still to come.</p><p>In today’s AI rundown:</p><p>Elon Musk’s $130B trial against OpenAI kicks off</p><p>Google finalizes Pentagon deal despite protests</p><p>Automate any manual task with Codex</p><p>Talkie is an AI that thinks it&#39;s 1930</p><p>4 new AI tools, community workflows, and more</p><p>LATEST DEVELOPMENTS</p><p>OPENAI</p><p>🏛️ <a href="https://www.cnn.com/2026/04/28/tech/elon-musk-sam-altman-openai?utm_source=www.therundown.ai&amp;utm_medium=newsletter&amp;utm_campaign=the-biggest-ai-trial-ever-kicks-off" target="_blank" rel="noreferrer">Elon Musk’s $130B trial against OpenAI kicks off</a></p><p>Image source: Images 2.0 / The Rundown</p><p>The Rundown: Elon Musk just <a href="https://www.cnn.com/2026/04/28/tech/elon-musk-sam-altman-openai?utm_source=www.therundown.ai&amp;utm_medium=newsletter&amp;utm_campaign=the-biggest-ai-trial-ever-kicks-off" target="_blank" rel="noreferrer">took the stand</a> in federal court as opening statements began in his $130B lawsuit against OpenAI, accusing CEO Sam Altman of &quot;stealing a charity&quot; — while OAI&#39;s lawyer told the jury Musk sued because he &quot;didn&#39;t get his way.&quot;</p><p>The details:</p><p>Musk&#39;s suit seeks $130B in damages, the ouster of Altman and Brockman from the board, and a forced unwind of OpenAI&#39;s recent for-profit conversion.</p><p>Musk said in his testimony that &quot;if a verdict comes out that it&#39;s OK to loot a charity, the entire foundation of charitable giving in America will be damaged”.</p><p>OAI’s legal team called Musk’s suit “sour grapes,” saying Musk didn’t like the success the company saw after his departure.</p><p>Microsoft’s legal team said Musk didn’t object to OAI’s structure until after its success as xAI’s competitor, and said it “knew nothing” of Altman’s 2023 firing.</p><p>Why it matters: This is just Day 1 of one of the most contentious court cases the tech world has seen, and the details are going to be juicy. With high-profile AI characters set to testify and with hundreds of pages of private messages about to spill into the public record, the next four weeks are going to be hard to look away from.</p><p>TOGETHER WITH TELEPORT</p><p>🛡️ <a href="https://www.beams.run/?utm_source=TheRundownAI&amp;utm_medium=Newsletter&amp;utm_campaign=AI&amp;utm_content=Insertion" target="_blank" rel="noreferrer">Trusted ephemeral runtime for infra agents</a></p><p><a href="https://www.beams.run/?utm_source=TheRundownAI&amp;utm_medium=Newsletter&amp;utm_campaign=AI&amp;utm_content=Insertion" target="_blank" rel="noreferrer"></a></p><p>The Rundown Running agents in production shouldn’t mean trading security for speed. Teleport Beams provisions an isolated VM and assigns identity via a short-lived certificate before an agent runs a single line — zero secrets, no IAM wrestling, no standing privileges.</p><p>Built for teams shipping real agents:</p><p>Each Beam runs in an isolated Firecracker VM</p><p>Supports coding agents, sandboxed apps, and agentic jobs</p><p>Fully auditable, with identity and access tied to every session</p><p><a href="https://www.beams.run/?utm_source=TheRundownAI&amp;utm_medium=Newsletter&amp;utm_campaign=AI&amp;utm_content=Insertion" target="_blank" rel="noreferrer">Explore Beams</a>.</p><p>GOOGLE</p><p>🪖 <a href="https://www.theinformation.com/articles/google-signs-classified-ai-deal-pentagon-amid-employee-opposition?utm_source=www.therundown.ai&amp;utm_medium=newsletter&amp;utm_campaign=the-biggest-ai-trial-ever-kicks-off" target="_blank" rel="noreferrer">Google finalizes Pentagon deal despite protests</a></p><p>Image source: Images 2.0 / The Rundown</p><p>The Rundown: Google <a href="https://www.theinformation.com/articles/google-signs-classified-ai-deal-pentagon-amid-employee-opposition?utm_source=www.therundown.ai&amp;utm_medium=newsletter&amp;utm_campaign=the-biggest-ai-trial-ever-kicks-off" target="_blank" rel="noreferrer">signed</a> a classified AI deal with the Pentagon, opening its models to &quot;any lawful government purpose,&quot; the same week that 600+ staffers wrote an open letter to CEO Sundar Pichai, calling to reject the use of AI for military purposes.</p><p>The details:</p><p>More than 600 Google employees <a href="https://www.washingtonpost.com/technology/2026/04/27/google-employees-letter-ai-pentagon/?utm_source=www.therundown.ai&amp;utm_medium=newsletter&amp;utm_campaign=the-biggest-ai-trial-ever-kicks-off" target="_blank" rel="noreferrer">sent</a> Pichai a letter on Monday asking him to “refuse to make our AI systems available for classified workloads.”</p><p>The Information reported that the contract opens Google&#39;s AI to “any lawful government purpose”, with no legal right to veto how the Pentagon uses it.</p><p>OAI and xAI inked <a href="https://openai.com/index/our-agreement-with-the-department-of-war/?utm_source=www.therundown.ai&amp;utm_medium=newsletter&amp;utm_campaign=the-biggest-ai-trial-ever-kicks-off" target="_blank" rel="noreferrer">deals</a> with the Pentagon last month, with Anthropic currently <a href="https://www.rundown.ai/articles/anthropic-takes-us-government-to-court?utm_source=www.therundown.ai&amp;utm_medium=newsletter&amp;utm_campaign=the-biggest-ai-trial-ever-kicks-off" target="_blank" rel="noreferrer">fighting</a> in court after being blacklisted for not dropping its guardrails.</p><p>Google&#39;s no-weapons pledge was scrubbed from its <a href="https://ai.google/principles/?utm_source=www.therundown.ai&amp;utm_medium=newsletter&amp;utm_campaign=the-biggest-ai-trial-ever-kicks-off" target="_blank" rel="noreferrer">AI principles</a> in 2025, after it was implemented in 2018 following successful <a href="https://www.nytimes.com/2018/04/04/technology/google-letter-ceo-pentagon-project.html?utm_source=www.therundown.ai&amp;utm_medium=newsletter&amp;utm_campaign=the-biggest-ai-trial-ever-kicks-off" target="_blank" rel="noreferrer">staff protests</a>.</p><p>Why it matters: The Pentagon drama might still feel fresh in the OAI-vs-Anthropic rivalry, but it’s not discouraging another top AI lab from making a similar deal. Google’s now wading into a messy territory from a PR and internal perspective, and time will tell if the same backlash we saw with ChatGPT now comes to Gemini’s doorstep.</p><p>AI TRAINING</p><p>✅ <a href="https://app.therundown.ai/guides/automate-any-manual-task-with-codex?utm_source=www.therundown.ai&amp;utm_medium=newsletter&amp;utm_campaign=the-biggest-ai-trial-ever-kicks-off" target="_blank" rel="noreferrer">Automate any manual task with Codex</a></p><p><a href="https://app.therundown.ai/guides/automate-any-manual-task-with-codex?utm_source=www.therundown.ai&amp;utm_medium=newsletter&amp;utm_campaign=the-biggest-ai-trial-ever-kicks-off" target="_blank" rel="noreferrer"></a></p><p>The Rundown: In this guide, you will learn how to let OpenAI’s Codex click through any annoying, repetitive work using Computer Use on Mac or Windows.</p><p>Step-by-step:</p><p>Open Codex, go to Plugins, find and enable the Computer Use plugin, and then start a new task</p><p>Open the permissions menu and switch from Default permissions to Full access. Confirm any prompts</p><p>Give a real task, like: “Open Chrome and debug the UI of this web page <a href="https://localhost:3000/?utm_source=www.therundown.ai&amp;utm_medium=newsletter&amp;utm_campaign=the-biggest-ai-trial-ever-kicks-off" target="_blank" rel="noreferrer">http://localhost:3000/</a>. Click through, reproduce the bug I describe, then tell me what you think is causing it. If not sure, ask before making changes”</p><p>Pro tip: Codex can automate repetitive workflows in local apps, too. Try it for Photoshop exports, Premiere cleanup, file renaming, or any other tool.</p><p>PRESENTED BY TELY AI</p><p>💬 <a href="https://www.tely.ai/?utm_source=newsletter&amp;utm_medium=email&amp;utm_campaign=rundown-jul-25" target="_blank" rel="noreferrer">Market leaders get leads from ChatGPT and Google</a></p><p><a href="https://www.tely.ai/?utm_source=newsletter&amp;utm_medium=email&amp;utm_campaign=rundown-jul-25" target="_blank" rel="noreferrer"></a></p><p>The Rundown: Your buyers are asking AI questions — and AI is answering with your competitors, not you. Tely makes AI like ChatGPT, Google, and Claude recommend your business instead.</p><p>With Tely AI, you can:</p><p>Get recommended in ChatGPT, Google, Perplexity, and Claude in as little as 1 week</p><p>Fully hands-off: no writers, no agencies, no managing content</p><p>Costs less than hiring freelancers or maintaining a marketing team</p><p>Ideal for niche industries where expertise matters</p><p><a href="https://www.tely.ai/?utm_source=newsletter&amp;utm_medium=email&amp;utm_campaign=rundown-jul-25" target="_blank" rel="noreferrer">Get leads from Google and ChatGPT on autopilot</a>.</p><p>AI RESEARCH</p><p>🕰️ <a href="https://talkie-lm.com/introducing-talkie?utm_source=www.therundown.ai&amp;utm_medium=newsletter&amp;utm_campaign=the-biggest-ai-trial-ever-kicks-off" target="_blank" rel="noreferrer">Talkie is an AI that thinks it&#39;s 1930</a></p><p>Image source: Images 2.0 / The Rundown</p><p>The Rundown: Researchers Nick Levine, David Duvenaud (fmr. Anthropic), and Alec Radford (fmr. OpenAI) <a href="https://talkie-lm.com/introducing-talkie?utm_source=www.therundown.ai&amp;utm_medium=newsletter&amp;utm_campaign=the-biggest-ai-trial-ever-kicks-off" target="_blank" rel="noreferrer">demoed</a> Talkie, a 13B ‘vintage’ AI model trained only on text from before 1931, built to test how AI thinks when its worldview predates the internet.</p><p>The details:</p><p>Talkie was trained on 260B tokens of pre-1931 books, newspapers, journals, patents, and case law, all now in the US public domain.</p><p>To teach talkie to chat without modern data, the team pulled instructions from etiquette manuals and cookbooks, with Claude Sonnet 4.6 grading the answers.</p><p>The coding language Python didn’t exist in 1930, but Talkie wrote working code by flipping a plus sign to a minus sign in an example, proving it can generalize.</p><p>AI benchmarks get poisoned when models train on their own test data — talkie sidesteps that, with a GPT-3-level version coming next.</p><p>Why it matters: Today&#39;s frontier models all sound vaguely similar because they all read roughly the same modern web. Talkie is definitely cut from a different cloth — but the Python coding anecdote is a fascinating part of the experiment that shows what kind of learning and reasoning is potentially going on beneath the original training data.</p><p>QUICK HITS</p><p>🛠️ <a href="https://www.rundown.ai/tools?utm_source=www.therundown.ai&amp;utm_medium=newsletter&amp;utm_campaign=the-biggest-ai-trial-ever-kicks-off" target="_blank" rel="noreferrer">Trending AI Tools</a></p><p>📊 <a href="https://www.rundown.ai/tools/replit-slides?utm_source=www.therundown.ai&amp;utm_medium=newsletter&amp;utm_campaign=the-biggest-ai-trial-ever-kicks-off" target="_blank" rel="noreferrer">Replit Slides</a> - Create polished, stunning slides in seconds with AI</p><p>🤖 <a href="https://www.rundown.ai/tools/nemotron-3-nano-omni?utm_source=www.therundown.ai&amp;utm_medium=newsletter&amp;utm_campaign=the-biggest-ai-trial-ever-kicks-off" target="_blank" rel="noreferrer">Nemotron 3 Nano Omni</a> - NVIDIA&#39;s open AI combining vision, audio, text</p><p>🌎 <a href="https://www.rundown.ai/tools/echo-2?utm_source=www.therundown.ai&amp;utm_medium=newsletter&amp;utm_campaign=the-biggest-ai-trial-ever-kicks-off" target="_blank" rel="noreferrer">Echo-2</a> - SpAItial’s new SOTA text-to-3D world model</p><p>⚙️ <a href="https://www.rundown.ai/tools/workflows?utm_source=www.therundown.ai&amp;utm_medium=newsletter&amp;utm_campaign=the-biggest-ai-trial-ever-kicks-off" target="_blank" rel="noreferrer">Workflows</a> - Mistral&#39;s enterprise tool for chaining AI agents</p><p>📰 <a href="https://www.rundown.ai/?utm_source=www.therundown.ai&amp;utm_medium=newsletter&amp;utm_campaign=the-biggest-ai-trial-ever-kicks-off" target="_blank" rel="noreferrer">Everything else in AI today</a></p><p>OpenAI <a href="https://openai.com/index/openai-on-aws/?utm_source=www.therundown.ai&amp;utm_medium=newsletter&amp;utm_campaign=the-biggest-ai-trial-ever-kicks-off" target="_blank" rel="noreferrer">announced</a> that GPT-5.5, Codex, and Managed Agents are now available via Amazon Bedrock, coming a day after its new contract <a href="https://www.rundown.ai/articles/openai-and-microsoft-new-open-relationship?utm_source=www.therundown.ai&amp;utm_medium=newsletter&amp;utm_campaign=the-biggest-ai-trial-ever-kicks-off" target="_blank" rel="noreferrer">restructure</a> with Microsoft.</p><p>NVIDIA <a href="http://www.rundown.ai/tools/nemotron-3-nano-omni?utm_source=www.therundown.ai&amp;utm_medium=newsletter&amp;utm_campaign=the-biggest-ai-trial-ever-kicks-off" target="_blank" rel="noreferrer">released</a> Nemotron 3 Nano Omni, a new open model that can handle vision, audio, and text at 9x the speed of rival open multimodal models.</p><p>The WSJ <a href="https://www.wsj.com/tech/ai/openai-misses-key-revenue-user-targets-in-high-stakes-sprint-toward-ipo-94a95273?utm_source=www.therundown.ai&amp;utm_medium=newsletter&amp;utm_campaign=the-biggest-ai-trial-ever-kicks-off" target="_blank" rel="noreferrer">reported</a> that OAI fell short of its targets for revenue and user growth, with CFO Sarah Friar questioning its massive spending — with OAI calling it “ludicrous.”</p><p>Anthropic <a href="https://www.anthropic.com/news/claude-for-creative-work?utm_source=www.therundown.ai&amp;utm_medium=newsletter&amp;utm_campaign=the-biggest-ai-trial-ever-kicks-off" target="_blank" rel="noreferrer">added</a> new connectors for a broader range of creative workflows, including apps like Blender, Adobe Creative Cloud, Autodesk Fusion, SketchUp, and more.</p><p>Xiaomi <a href="https://mimo.xiaomi.com/mimo-v2-5-pro?utm_source=www.therundown.ai&amp;utm_medium=newsletter&amp;utm_campaign=the-biggest-ai-trial-ever-kicks-off" target="_blank" rel="noreferrer">open-sourced</a> MiMo-V2.5-Pro, which ties Kimi K2.6 on Artificial Analysis’ leaderboard, featuring a 1M context window and strong efficiency for agentic tasks.</p><p>SpAItial <a href="https://spaitial.ai/blog/echo-2-release?utm_source=www.therundown.ai&amp;utm_medium=newsletter&amp;utm_campaign=the-biggest-ai-trial-ever-kicks-off" target="_blank" rel="noreferrer">launched</a> Echo-2, a new SOTA world model that turns text or photos into explorable 3D worlds, claiming to beat World Labs&#39; Marble 1.1 across benchmarks.</p><p>COMMUNITY</p><p>🤝 <a href="https://www.videoask.com/ffohxg3vc?utm_source=www.therundown.ai&amp;utm_medium=newsletter&amp;utm_campaign=the-biggest-ai-trial-ever-kicks-off" target="_blank" rel="noreferrer">Community AI workflows</a></p><p>Every newsletter, we showcase how a reader is using AI to work smarter, save time, or make life easier.</p><p>Today’s workflow comes from reader Alan C. in Ontario, Canada:</p><p>&quot;I used AI to resolve what looked like a furnace failure during a cold night without calling a technician. After installing a Google Nest Thermostat about a year ago, my system started making a loud ‘revving’ noise and flashing error codes (2 and 7) that pointed to pressure switch or hardware faults.</p><p>I photographed the control board and wiring and uploaded them to Google Gemini. It identified the furnace, traced the issue to thermostat power stealing, and flagged a wiring phasing error. It then guided a simple ‘G-to-C’ wire conversion to provide stable power, along with steps to clear lockouts and verify readings.</p><p>Within an hour, the noise stopped, error codes cleared, and the system stabilized to normal operation. It saved me about $300 HVAC tech service call, and I avoided a night in the cold.&quot;</p><p>How do you use AI? Tell us <a href="https://www.videoask.com/ffohxg3vc?utm_source=www.therundown.ai&amp;utm_medium=newsletter&amp;utm_campaign=the-biggest-ai-trial-ever-kicks-off" target="_blank" rel="noreferrer">here</a>.</p><p>🎓 <a href="https://app.therundown.ai/?utm_source=www.therundown.ai&amp;utm_medium=newsletter&amp;utm_campaign=the-biggest-ai-trial-ever-kicks-off" target="_blank" rel="noreferrer">Highlights: News, Guides &amp; Events</a></p><p>Read our last AI newsletter: <a href="https://www.rundown.ai/articles/openai-and-microsoft-new-open-relationship?utm_source=www.therundown.ai&amp;utm_medium=newsletter&amp;utm_campaign=the-biggest-ai-trial-ever-kicks-off" target="_blank" rel="noreferrer">OpenAI and Microsoft’s new open relationship</a></p><p>Read our last Tech newsletter: <a href="https://www.rundown.ai/articles/samsung-meta-ray-ban-rival-just-leaked?utm_source=www.therundown.ai&amp;utm_medium=newsletter&amp;utm_campaign=the-biggest-ai-trial-ever-kicks-off" target="_blank" rel="noreferrer">Samsung’s Meta Ray-Ban rival just leaked</a></p><p>Read our last Robotics newsletter: <a href="https://www.rundown.ai/articles/the-chinese-robot-ban-is-coming?utm_source=www.therundown.ai&amp;utm_medium=newsletter&amp;utm_campaign=the-biggest-ai-trial-ever-kicks-off" target="_blank" rel="noreferrer">The Chinese robot ban is coming</a></p><p>Today’s AI tool guide: <a href="https://app.therundown.ai/guides/automate-any-manual-task-with-codex?utm_source=www.therundown.ai&amp;utm_medium=newsletter&amp;utm_campaign=the-biggest-ai-trial-ever-kicks-off" target="_blank" rel="noreferrer">Automate any manual task with Codex</a></p><p>RSVP to workshop Thursday @ 2PM EST: <a href="https://app.therundown.ai/calendar-events/69e77469e7e908f6d4ebdf72?utm_source=www.therundown.ai&amp;utm_medium=newsletter&amp;utm_campaign=the-biggest-ai-trial-ever-kicks-off" target="_blank" rel="noreferrer">Codex for non-technical operators</a></p><p>See you soon,</p><p>Rowan, Joey, Zach, Shubham, and Jennifer — the humans behind The Rundown</p><hr>',104)])])}const d=t(i,[["render",o]]);export{w as __pageData,d as default};
